exec('import csv,json,math,os,re,sqlite3\nfrom pathlib import Path\nfrom uuid import uuid4\nfrom fastapi import FastAPI,File,Form,HTTPException,UploadFile\nfrom fastapi.responses import FileResponse\nfrom fastapi.staticfiles import StaticFiles\nfrom pydantic import BaseModel\nfrom openpyxl import Workbook\nBASE=Path(os.getenv("APP_DATA_DIR","data"))\nUPLOAD_DIR=BASE/"uploads"\nOUTPUT_DIR=BASE/"outputs"\nDB=BASE/"app.sqlite3"\nfor d in (BASE,UPLOAD_DIR,OUTPUT_DIR):\n    d.mkdir(parents=True,exist_ok=True)\nALLOW={x.strip() for x in os.getenv("NOTE_ID_ALLOWLIST","demo-note-001,demo-note-002,member-test").split(",") if x.strip()}\nAUTH_MODE=os.getenv("NOTE_AUTH_MODE","allowlist")\nLIFF_ID=os.getenv("LIFF_ID","")\nTARGET_DRIVE_FOLDER_ID=os.getenv("TARGET_DRIVE_FOLDER_ID","11cA-CrY7rjlQlzdXywpT3i7PLRrXxOgD")\napp=FastAPI(title="ボリューム検討チャット Clone",version="1.0.0")\nstatic_dir=Path(__file__).parent/"static"\nif static_dir.exists():\n    app.mount("/static",StaticFiles(directory=static_dir),name="static")\nclass SessionRequest(BaseModel):\n    note_id:str\ndef _conn():\n    c=sqlite3.connect(DB)\n    c.row_factory=sqlite3.Row\n    return c\ndef init_db():\n    with _conn() as c:\n        c.executescript("CREATE TABLE IF NOT EXISTS sessions(token TEXT PRIMARY KEY,note_id TEXT NOT NULL);CREATE TABLE IF NOT EXISTS jobs(job_id TEXT PRIMARY KEY,token TEXT,note_id TEXT,result_json TEXT,output_dir TEXT);")\ninit_db()\ndef _allowed(note_id):\n    note_id=note_id.strip()\n    return bool(note_id) and (AUTH_MODE.lower()=="open" or note_id in ALLOW)\ndef _num(pattern,text):\n    m=re.search(pattern,text,re.I)\n    return float(m.group(1)) if m else None\nZONINGS=["第一種低層住居専用地域","第二種低層住居専用地域","第一種中高層住居専用地域","第二種中高層住居専用地域","第一種住居地域","第二種住居地域","準住居地域","田園住居地域","近隣商業地域","商業地域","準工業地域","工業地域","工業専用地域"]\ndef _zoning(text):\n    for z in ZONINGS:\n        if z in text:\n            return z\n    m=re.search("用途地域[:： ]*([^\\n]+)",text)\n    return m.group(1).strip() if m else None\ndef _address(text):\n    for line in text.splitlines():\n        if line.startswith(("所在地","住所","地番")):\n            return re.sub("^(所在地|住所|地番)[:： ]*","",line).strip()\n    return None\ndef analyze_text(text):\n    land=_num("([0-9]+(?:[.][0-9]+)?)(?:㎡|m2|m²|平米)",text)\n    tsubo=_num("([0-9]+(?:[.][0-9]+)?)坪",text)\n    if land is None and tsubo is not None:\n        land=tsubo*3.305785\n    bcr=_num("(?:建ぺい率|建蔽率|BCR)[^0-9]{0,20}([0-9]{2,4}(?:[.][0-9]+)?)",text)\n    far=_num("(?:容積率|FAR)[^0-9]{0,20}([0-9]{2,4}(?:[.][0-9]+)?)",text)\n    road=_num("(?:前面道路|道路幅員|幅員)[^0-9]{0,20}([0-9]+(?:[.][0-9]+)?)",text)\n    avg=_num("(?:平均住戸面積|平均住戸|1戸|一戸)[^0-9]{0,20}([0-9]+(?:[.][0-9]+)?)(?:㎡|m2|m²|平米)",text) or 45.0\n    zone=_zoning(text)\n    coef=0.6 if zone and any(k in zone for k in ["商業","工業"]) else 0.4\n    road_far=road*coef*100 if road is not None else None\n    applied=far\n    if far is not None and road is not None and road<12:\n        applied=min(far,road_far)\n    footprint=land*bcr/100 if land is not None and bcr is not None else None\n    total=land*applied/100 if land is not None and applied is not None else None\n    rentable=total*0.82 if total is not None else None\n    floors=max(1,math.ceil(total/footprint)) if total and footprint else None\n    units=max(1,math.floor(rentable/avg)) if rentable else None\n    missing=[k for k,v in {"土地面積":land,"建ぺい率":bcr,"容積率":far,"前面道路幅員":road,"用途地域":zone}.items() if v is None]\n    cautions=["この結果は初期検討用の概算であり、建築可否・収益性・法適合を保証しません。","斜線制限、日影規制、高度地区、防火地域、条例、接道、敷地形状は別途確認してください。"]\n    if road_far is not None and far is not None and applied!=far:\n        cautions.append("前面道路幅員による容積率制限を反映しています。")\n    if missing:\n        cautions.append("不足項目: "+", ".join(missing))\n    return {"address":_address(text),"zoning":zone,"inputs":{"land_area_m2":round(land,2) if land is not None else None,"building_coverage_ratio_percent":bcr,"floor_area_ratio_percent":far,"road_width_m":road,"avg_unit_size_m2":avg},"calculation":{"road_limited_far_percent":round(road_far,2) if road_far is not None else None,"applied_far_percent":round(applied,2) if applied is not None else None,"max_footprint_m2":round(footprint,2) if footprint is not None else None,"max_total_floor_area_m2":round(total,2) if total is not None else None,"estimated_rentable_area_m2":round(rentable,2) if rentable is not None else None,"estimated_floors":floors,"estimated_units":units},"confidence":round(max(0.2,1.0-0.13*len(missing)),2),"cautions":cautions}\ndef _flatten(prefix,value,rows):\n    if isinstance(value,dict):\n        for k,v in value.items():\n            _flatten((prefix+"."+k) if prefix else k,v,rows)\n    elif isinstance(value,list):\n        rows.append((prefix," / ".join(str(x) for x in value)))\n    else:\n        rows.append((prefix,value))\ndef write_exports(job_id,result,extracted_text,out_dir):\n    out_dir.mkdir(parents=True,exist_ok=True)\n    rows=[]\n    _flatten("",result,rows)\n    csv_path=out_dir/(job_id+".csv")\n    with csv_path.open("w",newline="",encoding="utf-8-sig") as fp:\n        w=csv.writer(fp); w.writerow(["key","value"]); w.writerows(rows)\n    txt_path=out_dir/(job_id+".txt")\n    with txt_path.open("w",encoding="utf-8") as fp:\n        fp.write(chr(10).join([f"{k}: {v}" for k,v in rows])+chr(10)+"--- extracted text ---"+chr(10)+extracted_text)\n    xlsx_path=out_dir/(job_id+".xlsx")\n    wb=Workbook(); ws=wb.active; ws.title="Summary"; ws.append(["key","value"])\n    for row in rows:\n        ws.append(list(row))\n    tx=wb.create_sheet("ExtractedText"); tx.append(["text"]); tx.append([extracted_text]); wb.save(xlsx_path)\n    return {"csv":csv_path,"txt":txt_path,"xlsx":xlsx_path}\n@app.get("/")\ndef index():\n    p=static_dir/"index.html"\n    return FileResponse(p) if p.exists() else {"app":"ボリューム検討チャット Clone"}\n@app.get("/api/health")\ndef health():\n    return {"status":"ok","app":"ボリューム検討チャット Clone"}\n@app.get("/api/config")\ndef config():\n    return {"app_name":"ボリューム検討チャット Clone","liff_id":LIFF_ID,"note_auth_mode":AUTH_MODE,"demo_note_ids":sorted(ALLOW) if AUTH_MODE=="allowlist" else [],"target_drive_folder_id":TARGET_DRIVE_FOLDER_ID}\n@app.post("/api/session")\ndef create_session(payload:SessionRequest):\n    note_id=payload.note_id.strip()\n    if not _allowed(note_id):\n        raise HTTPException(status_code=403,detail="note ID is not allowed")\n    token=uuid4().hex\n    with _conn() as c:\n        c.execute("INSERT INTO sessions(token,note_id) VALUES(?,?)",(token,note_id))\n    return {"token":token,"note_id":note_id}\n@app.post("/api/analyze")\nasync def analyze(token:str=Form(...),file:UploadFile=File(...),manual_text:str=Form("")):\n    with _conn() as c:\n        s=c.execute("SELECT * FROM sessions WHERE token=?",(token,)).fetchone()\n    if s is None:\n        raise HTTPException(status_code=401,detail="invalid session token")\n    job_id=uuid4().hex; safe_name=Path(file.filename or "upload.bin").name; content=await file.read(); upload_path=UPLOAD_DIR/(job_id+"_"+safe_name); upload_path.write_bytes(content)\n    extracted=manual_text.strip()+chr(10)+f"upload_name: {safe_name}"+chr(10)+f"file_size_bytes: {len(content)}"\n    result=analyze_text(extracted); out_dir=OUTPUT_DIR/job_id; write_exports(job_id,result,extracted,out_dir)\n    with _conn() as c:\n        c.execute("INSERT INTO jobs(job_id,token,note_id,result_json,output_dir) VALUES(?,?,?,?,?)",(job_id,token,s["note_id"],json.dumps(result,ensure_ascii=False),str(out_dir)))\n    return {"job_id":job_id,"result":result,"exports":{"csv":f"/api/jobs/{job_id}/exports/csv","xlsx":f"/api/jobs/{job_id}/exports/xlsx","txt":f"/api/jobs/{job_id}/exports/txt"}}\n@app.get("/api/jobs/{job_id}")\ndef get_job(job_id):\n    with _conn() as c:\n        row=c.execute("SELECT * FROM jobs WHERE job_id=?",(job_id,)).fetchone()\n    if row is None:\n        raise HTTPException(status_code=404,detail="job not found")\n    d=dict(row); d["result"]=json.loads(d.pop("result_json")); return d\n@app.get("/api/jobs/{job_id}/exports/{kind}")\ndef download(job_id,kind):\n    if kind not in {"csv","xlsx","txt"}:\n        raise HTTPException(status_code=404,detail="unsupported export type")\n    with _conn() as c:\n        row=c.execute("SELECT output_dir FROM jobs WHERE job_id=?",(job_id,)).fetchone()\n    if row is None:\n        raise HTTPException(status_code=404,detail="job not found")\n    path=Path(row["output_dir"])/(job_id+"."+kind)\n    if not path.exists():\n        raise HTTPException(status_code=404,detail="export not found")\n    media={"csv":"text/csv","xlsx":"application/vnd.openxmlformats-officedocument.spreadsheetml.sheet","txt":"text/plain"}\n    return FileResponse(path,media_type=media[kind],filename=path.name)\n')